What does the following program print?

```cpp
#include <iostream>
#include <vector>

std::vector<int> make()
{
    std::vector<int> v { 1, 2, 3 };
    return v;
}

int main()
{
    std::vector<int> a { make() };
    std::cout << a.size() << '\n';
}
```

