What does this program print?

```cpp
#include <iostream>
#include <vector>

std::vector<int> doubled(std::vector<int> v)
{
    for (int& x : v)
        x *= 2;
    return v;
}

int main()
{
    std::vector<int> a { 3, 5, 7 };
    std::vector<int> b { doubled(a) };
    std::cout << b[1] << '\n';
}
```
